import{_ as t,a as o}from"./chunks/common-save-actions.BbCaQ7WW.js";import{_ as a,c as s,o as i,ag as n}from"./chunks/framework.DD2hp6gW.js";const r="/assets/bogo-selection.Dd5ygiGK.png",l="/assets/bogo-target-settings.DWNeQpYF.png",c="/assets/bogo-rule-setup.BEYgzorI.png",u="/assets/bogo-conditions-overview.CdW3R17Q.png",p="/assets/bogo-sidebar-exclude-sale-item.eLTRLsgs.png",d="/assets/bogo-sidebar-usage-limit.wleTCsD8.png",g="/assets/bogo-sidebar-schedule-dates.DOnY8VxJ.png",h="/assets/bogo-show-product-message.DynGJ7m2.png",m="/assets/bogo-product-message-format.lGo-XDAe.png",f="/assets/bogo-cart-message-format.Cexzasio.png",y="/assets/bogo-cart-message-location.9nT6BJfZ.png",G=JSON.parse('{"title":"Campaign Type: BOGO Discount (Buy X Get X)","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/bogo-discounts.md","filePath":"campaigns/bogo-discounts.md","lastUpdated":1770144771000}'),b={name:"campaigns/bogo-discounts.md"};function q(T,e,S,_,O,v){return i(),s("div",null,e[0]||(e[0]=[n('<h1 id="campaign-type-bogo-discount-buy-x-get-x" tabindex="-1">Campaign Type: BOGO Discount (Buy X Get X) <a class="header-anchor" href="#campaign-type-bogo-discount-buy-x-get-x" aria-label="Permalink to &quot;Campaign Type: BOGO Discount (Buy X Get X)&quot;">​</a></h1><p>A <strong>BOGO (Buy One, Get One)</strong> discount is a popular promotional tool that rewards customers with free or discounted items when they purchase a specific quantity of a product. This guide covers the <strong>&quot;Buy X Get X&quot;</strong> type, where the item the customer &quot;gets&quot; is the same as the item they &quot;buy&quot;.</p><p>This is the perfect campaign type for scenarios like:</p><ul><li>&quot;Buy 2 T-Shirts, Get 1 Free&quot;</li><li>&quot;Buy 3, Get 1 Free&quot; on specific items.</li></ul><p>This guide will walk you through every field required to set up this campaign type.</p><h2 id="step-1-select-your-campaign-type" tabindex="-1">Step 1: Select Your Campaign Type <a class="header-anchor" href="#step-1-select-your-campaign-type" aria-label="Permalink to &quot;Step 1: Select Your Campaign Type&quot;">​</a></h2><p>To begin, navigate to <strong>CampaignBay → Add Campaign</strong>.</p><p><img src="'+r+'" alt="Select BOGO Standard"></p><ul><li><strong>Select Discount Type:</strong> Choose <strong><code>Buy X Get X</code></strong> from the list. This will reveal the configuration fields for the standard BOGO offer, where the &quot;Buy&quot; item and the &quot;Get&quot; item are the same.</li></ul><p><img src="'+t+'" alt="Campaign Title"></p><ul><li><strong>Campaign Title:</strong> Give your campaign a clear and descriptive name (e.g., &quot;Hoodie BOGO Deal&quot;).</li></ul><p><img src="'+o+'" alt="Save Actions"></p><ul><li><strong>Select Status:</strong><ul><li><strong>Active:</strong> The campaign will be live as soon as its start time is reached.</li><li><strong>Inactive:</strong> The campaign will be saved as a draft.</li></ul></li></ul><h2 id="step-2-set-the-discount-target" tabindex="-1">Step 2: Set the Discount Target <a class="header-anchor" href="#step-2-set-the-discount-target" aria-label="Permalink to &quot;Step 2: Set the Discount Target&quot;">​</a></h2><p>This crucial step defines which products in your store are eligible for the BOGO offer.</p><p><img src="'+l+'" alt="Discount Target"></p><p>The <strong>DISCOUNT TARGET</strong> dropdown provides options to apply the offer to your entire store, specific products, or categories.</p><div class="info custom-block"><p class="custom-block-title">Learn More About Targeting</p><p>The &quot;Discount Target&quot; setting is a powerful feature shared by all campaign types. We&#39;ve created a dedicated guide to explain all of its options and conditional fields in detail.</p><p><strong><a href="./../core-concepts/targeting.html">Read the Full Guide: Targeting →</a></strong></p></div><h2 id="step-3-define-the-bogo-rule" tabindex="-1">Step 3: Define the BOGO Rule <a class="header-anchor" href="#step-3-define-the-bogo-rule" aria-label="Permalink to &quot;Step 3: Define the BOGO Rule&quot;">​</a></h2><p>This is the core logic of your campaign.</p><p><img src="'+c+'" alt="BOGO Rule Setup"></p><ul><li><strong>Buy X pieces:</strong> Enter the number of items the customer needs to purchase to trigger the offer (e.g., <code>2</code>).</li><li><strong>Get Y pieces:</strong> Enter the number of items the customer will receive for free (e.g., <code>1</code>).</li></ul><div class="tip custom-block"><p class="custom-block-title">How it works</p><p>If you set <strong>Buy 2 Get 1</strong> on a Hoodie, and a customer adds 2 Hoodies to their cart, 1 free Hoodie will be automatically added to the cart. If they add 4 Hoodies, 2 free Hoodies will be added.</p></div><h2 id="step-4-set-conditions-optional" tabindex="-1">Step 4: Set Conditions (Optional) <a class="header-anchor" href="#step-4-set-conditions-optional" aria-label="Permalink to &quot;Step 4: Set Conditions (Optional)&quot;">​</a></h2><p>You can add specific rules to restrict who can use this discount (e.g., specific User Roles).</p><p><img src="'+u+'" alt="Conditions Overview"></p><p><strong><a href="./../core-concepts/conditions.html">Read the Full Guide: How to Use Conditions →</a></strong></p><h2 id="step-5-set-other-configurations-optional" tabindex="-1">Step 5: Set Other Configurations (Optional) <a class="header-anchor" href="#step-5-set-other-configurations-optional" aria-label="Permalink to &quot;Step 5: Set Other Configurations (Optional)&quot;">​</a></h2><p>This section provides additional rules for your campaign.</p><p><img src="'+p+'" alt="Exclude Sale Item"></p><ul><li><strong>Exclude Sale Items:</strong> Check this box if you do not want this campaign&#39;s discount to apply to products that are already on sale in WooCommerce. This is useful for preventing &quot;double discounting.&quot;</li></ul><p><img src="'+d+'" alt="Enable Usage Limit"></p><ul><li><strong>Enable Usage Limit:</strong> Check this box to set a maximum number of times this campaign can be used across your entire store. Once the limit is reached, the campaign will automatically become inactive.</li></ul><h2 id="step-6-set-the-schedule-optional" tabindex="-1">Step 6: Set the Schedule (Optional) <a class="header-anchor" href="#step-6-set-the-schedule-optional" aria-label="Permalink to &quot;Step 6: Set the Schedule (Optional)&quot;">​</a></h2><p>You can optionally schedule your campaign to run during a specific time window. This section controls when your campaign will automatically start and end.</p><p><img src="'+g+'" alt="Enable Schedule"></p><ul><li><strong>Start Time / End Time:</strong> Use the date and time pickers to set the exact moment for the campaign to activate and expire.</li></ul><div class="tip custom-block"><p class="custom-block-title">Timezone Information</p><p>All dates and times are based on the timezone you have configured in your main WordPress settings under <strong>Settings → General → Timezone</strong>. The system automatically handles all UTC conversions for you.</p></div><div class="info custom-block"><p class="custom-block-title">Learn More About Automation</p><p>The status of your campaign is closely tied to the scheduling system, which uses WordPress Cron to automate activation and expiration.</p><p><strong><a href="./../core-concepts/scheduling-and-automation.html">Read the Full Guide: Scheduling &amp; Automation →</a></strong></p></div><h2 id="step-7-define-display-configurations" tabindex="-1">Step 7: Define Display Configurations <a class="header-anchor" href="#step-7-define-display-configurations" aria-label="Permalink to &quot;Step 7: Define Display Configurations&quot;">​</a></h2><p>This section is unique to BOGO campaigns and controls how the offer is communicated and applied.</p><ul><li><strong>Automatically Add Free Product To Cart:</strong> This is a powerful user experience feature. <ul><li><strong>If checked:</strong> When a customer adds the &quot;Buy Amount&quot; (e.g., 2 items), the free &quot;Get Quantity&quot; (e.g., 1 item) will be <strong>automatically added to their cart at no cost</strong>.</li><li><strong>If unchecked:</strong> The customer must manually add the total quantity to their cart (e.g., 3 items). The plugin will then automatically apply a discount equal to the price of the &quot;Get Quantity&quot; (1 item).</li></ul></li></ul><h3 id="messaging-options" tabindex="-1">Messaging Options <a class="header-anchor" href="#messaging-options" aria-label="Permalink to &quot;Messaging Options&quot;">​</a></h3><p><img src="'+h+'" alt="Show Promo Message"></p><ul><li><strong>Show BOGO Promotional Message at product page:</strong> Toggle this to enable or disable the custom message on the product page.</li></ul><p><img src="'+m+'" alt="Product Page Message"></p><ul><li><strong>Product Page Discount Message Format:</strong> Enter a message to display on the product page. Use placeholders like <code>{buy_quantity}</code> and <code>{get_quantity}</code>. <ul><li><em>Example:</em> <code>Buy {buy_quantity} and get {get_quantity} free!</code></li></ul></li></ul><p><img src="'+f+'" alt="Cart Page Message"></p><ul><li><strong>Cart Page Discount Message Format:</strong> Enter a message to display in the cart. Use <code>{title}</code> to show the campaign name. <ul><li><em>Example:</em> <code>Discount &#39;{title}&#39; has been applied!</code></li></ul></li></ul><p><img src="'+y+'" alt="Cart Message Location"></p><ul><li><strong>Cart Page Message Location:</strong> Choose where the cart message should appear (e.g., next to the line item name).</li></ul><h2 id="step-8-save-the-campaign" tabindex="-1">Step 8: Save the Campaign <a class="header-anchor" href="#step-8-save-the-campaign" aria-label="Permalink to &quot;Step 8: Save the Campaign&quot;">​</a></h2><p>Once you have configured all the options, click the <strong>Save Campaign</strong> button. You will be redirected to the &quot;All Campaigns&quot; list where you can see your new BOGO offer.</p><p>Next, learn how to create advanced BOGO deals where product X gives product Y.</p><ul><li><strong><a href="./bogo-advanced-discounts.html">BOGO Advanced (Buy X Get Y) →</a></strong></li></ul>',55)]))}const B=a(b,[["render",q]]);export{G as __pageData,B as default};
